import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Animated, Pressable, ScrollView, StatusBar, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { LinearGradient } from 'expo-linear-gradient';
import { MaterialCommunityIcons } from '@expo/vector-icons';

const VERSION = 'v0.2';
const KEY = 'drabornlife-v02-complete';
const LEGACY_KEYS = ['drabornlife-v01-complete', 'drabornlife-v021-clean'];
const REGIONS = ['Muratpaşa', 'Lara', 'Konyaaltı'];
const budgetNames = ['Kira', 'Depozito', 'Emlakçı / giriş masrafı', 'Beyaz eşya', 'Mobilya', 'Mutfak eşyaları', 'Ev temel ihtiyaçları', 'Çocuk odası', 'İlk ay yaşam gideri', 'Antalya eğlence / aquapark / aile aktiviteleri', 'GTA 6 seti', 'PS5 Pro', 'TV', 'Yeni motosiklet hedefi', 'Acil durum parası'];
const itemCategories = ['Kira / depozito', 'Beyaz eşya', 'Mobilya', 'Salon', 'Yatak odası', 'Çocuk odası', 'Mutfak', 'Banyo', 'Temizlik', 'Elektronik', 'GTA 6 seti', 'PS5 Pro', 'TV', 'Yeni motosiklet', 'İlk ay yaşam', 'Antalya eğlence', 'Diğer'];
const itemStatuses = ['Planlandı', 'Parası Birikti', 'Satın Alındı', 'Kuruldu', 'Vazgeçildi'];
const debtStatuses = ['Devam ediyor', 'Azaldı', 'Bitti', 'Ertelendi'];
const moveStatuses = ['Planlama', 'Para birikiyor', 'Ev araştırması başladı', 'Ev tutuldu', 'Eşyalar alınıyor', 'Kurulum başladı', 'Antalya’ya taşınıldı'];
const motoStatuses = ['Planlandı', 'Para birikiyor', 'Eski motor satıldı', 'Yeni motor alındı'];
const noteCategories = ['Genel', 'Para', 'Ev', 'Eşya', 'Antalya', 'Aile', 'Fikir', 'Acil'];
const financeModes = [
  ['income', 'Gelir', 'cash-plus', ['#19D3FF', '#2E6BFF']],
  ['expense', 'Gider', 'cart-arrow-down', ['#FF4D8D', '#FF9E2C']],
  ['saving', 'Birikim', 'piggy-bank', ['#0FE0A0', '#22D3EE']],
  ['debt', 'Borç', 'alert-circle', ['#8B5CF6', '#FF4D6D']]
];
const categoryMap = {
  income: ['Günlük kazanç', 'İş geliri', 'Ek gelir', 'Satış geliri', 'Borç tahsilatı', 'Diğer'],
  expense: ['Ev gideri', 'Market', 'Ulaşım', 'Çocuk', 'Borç ödemesi', 'Antalya hazırlık', 'Eğlence', 'Diğer'],
  saving: ['Günlük birikim', 'İş geliri', 'Ek gelir', 'Motor', 'GTA 6 seti', 'Acil durum', 'Diğer'],
  debt: ['Kredi kartı', 'Kişisel borç', 'Taksit', 'Elden borç', 'Diğer']
};
const catIcons = {
  'Günlük kazanç': 'cash-fast', 'İş geliri': 'briefcase', 'Ek gelir': 'plus-circle', 'Satış geliri': 'tag-multiple', 'Borç tahsilatı': 'account-cash',
  'Ev gideri': 'home', Market: 'cart', Ulaşım: 'car', Çocuk: 'baby-face', 'Borç ödemesi': 'credit-card-check', 'Antalya hazırlık': 'palm-tree', Eğlence: 'party-popper',
  'Günlük birikim': 'piggy-bank', Motor: 'motorbike', 'GTA 6 seti': 'gamepad-variant', 'Acil durum': 'shield-alert',
  'Kredi kartı': 'credit-card', 'Kişisel borç': 'account-alert', Taksit: 'calendar-clock', 'Elden borç': 'hand-coin', Diğer: 'dots-horizontal-circle'
};
const makeBudgets = () => budgetNames.map((name, i) => ({ id: `budget-${i}`, name, estimate: 0, actual: 0, note: '' }));
const makeGta = () => [
  { id: 'ps5', name: 'PS5 Pro', cost: 0, status: 'Planlandı' },
  { id: 'tv', name: 'TV', cost: 0, status: 'Planlandı' },
  { id: 'game', name: 'GTA 6 oyunu', cost: 0, status: 'Planlandı' }
];
const emptyData = {
  settings: { targetBudget: 650000, targetDate: '2026-10-31', currency: 'TL', theme: 'dark' },
  budgetCategories: makeBudgets(), incomes: [], expenses: [], savings: [], debts: [], items: [], houses: [], schools: [], checklist: [], notes: [], activities: [],
  motorcycle: { price: 130000, saved: 0, includeInBudget: true, status: 'Planlandı', note: 'Eski motosiklet satılacak, Antalya’da sıfır motosiklet alınacak.' },
  gtaGoal: { targetDate: '2026-11-19', note: 'GTA 6 çıkmadan önce taşınma tamamlanmalı ve set hazır olmalı.', items: makeGta() },
  relocation: { city: 'Antalya', status: 'Planlama', regions: 'Muratpaşa / Lara / Konyaaltı', homeGoal: 'Denize yakın, yeni bina, temiz ev', moveNote: 'Antakya’dan nakliye yok; birkaç valizle gidilecek. Eşyalar Antalya’dan sıfır alınacak.' },
  family: { note: 'Evimize tatil hayatını taşıyoruz.', motivation: 'Deniz, sahil, aquapark, aile aktiviteleri ve Antalya’da yeni yaşam.' }
};

const num = (v) => {
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  const raw = String(v ?? '').trim().replace(/\s/g, '');
  if (!raw) return 0;
  if (raw.includes(',')) return Number(raw.replace(/\./g, '').replace(',', '.')) || 0;
  const dotParts = raw.split('.');
  if (dotParts.length > 1 && dotParts.slice(1).every((p) => p.length === 3)) return Number(raw.replace(/\./g, '')) || 0;
  return Number(raw) || 0;
};
const money = (v) => `${Math.round(num(v)).toLocaleString('tr-TR')} TL`;
const uid = () => `${Date.now()}-${Math.random().toString(16).slice(2)}`;
const today = () => new Date().toISOString().slice(0, 10);
const daysLeft = (d) => Math.max(0, Math.ceil((new Date(`${d}T23:59:59`).getTime() - Date.now()) / 86400000));
const pct = (a, b) => (!b ? 0 : Math.max(0, Math.min(100, Math.round((a / b) * 100))));
const sum = (arr, key = 'amount') => arr.reduce((s, x) => s + num(x[key]), 0);
const sameDay = (d) => (d || '').slice(0, 10) === today();
const sameMonth = (d) => (d || '').slice(0, 7) === today().slice(0, 7);
const last7 = (d) => Date.now() - new Date(d || 0).getTime() <= 7 * 86400000;

export default function App() {
  const [data, setData] = useState(emptyData);
  const [ready, setReady] = useState(false);
  const [tab, setTab] = useState('panel');
  const [budgetTab, setBudgetTab] = useState('budget');
  const [lifeTab, setLifeTab] = useState('plan');
  const [financeMode, setFinanceMode] = useState('income');
  const [editing, setEditing] = useState(null);
  const [finance, setFinance] = useState({ title: '', amount: '', paid: '', date: today(), dueDate: '', category: categoryMap.income[0], status: 'Devam ediyor', note: '' });
  const [payment, setPayment] = useState({});
  const [budget, setBudget] = useState({ name: '', estimate: '', actual: '', note: '' });
  const [item, setItem] = useState({ name: '', category: itemCategories[0], estimate: '', actual: '', priority: 'Orta', note: '' });
  const [house, setHouse] = useState({ title: '', region: REGIONS[0], rent: '', deposit: '', buildingAge: '', note: '' });
  const [school, setSchool] = useState({ name: '', region: REGIONS[0], monthly: '', ageGroup: '5 yaş', note: '' });
  const [task, setTask] = useState('');
  const [activity, setActivity] = useState('');
  const [note, setNote] = useState({ title: '', category: noteCategories[0], body: '' });
  const [backup, setBackup] = useState('');
  const [toast, setToast] = useState('');
  const float = useRef(new Animated.Value(0)).current;
  const fade = useRef(new Animated.Value(1)).current;

  useEffect(() => { (async () => { let raw = await AsyncStorage.getItem(KEY); if (!raw) { for (const k of LEGACY_KEYS) { raw = await AsyncStorage.getItem(k); if (raw) break; } } if (raw) setData(merge(JSON.parse(raw))); setReady(true); })().catch(() => setReady(true)); }, []);
  useEffect(() => { if (ready) AsyncStorage.setItem(KEY, JSON.stringify(data)).catch(() => {}); }, [data, ready]);
  useEffect(() => { Animated.loop(Animated.sequence([Animated.timing(float, { toValue: 1, duration: 2600, useNativeDriver: true }), Animated.timing(float, { toValue: 0, duration: 2600, useNativeDriver: true })])).start(); }, [float]);
  useEffect(() => { fade.setValue(0); Animated.timing(fade, { toValue: 1, duration: 260, useNativeDriver: true }).start(); }, [tab, budgetTab, lifeTab, fade]);

  const theme = getTheme(data.settings.theme);
  const stats = useMemo(() => getStats(data), [data]);
  const save = (next) => setData({ ...next, version: VERSION, updatedAt: new Date().toISOString() });
  const say = (msg) => setToast(msg);

  function switchFinanceMode(mode) { setFinanceMode(mode); setEditing(null); setFinance({ title: '', amount: '', paid: '', date: today(), dueDate: '', category: categoryMap[mode][0], status: 'Devam ediyor', note: '' }); }
  function addOrUpdateFinance() { if (!finance.title.trim() || !num(finance.amount)) return say('Başlık ve tutar gir.'); const map = { income: 'incomes', expense: 'expenses', saving: 'savings', debt: 'debts' }; const key = map[financeMode]; const base = { id: editing?.id || uid(), title: finance.title.trim(), amount: num(finance.amount), category: finance.category || 'Genel', date: finance.date || today(), note: finance.note }; const row = financeMode === 'debt' ? { ...base, paid: num(finance.paid), dueDate: finance.dueDate, status: finance.status || 'Devam ediyor' } : base; save({ ...data, [key]: editing?.key === key ? data[key].map((x) => x.id === editing.id ? row : x) : [row, ...data[key]] }); setEditing(null); setFinance({ title: '', amount: '', paid: '', date: today(), dueDate: '', category: categoryMap[financeMode][0], status: 'Devam ediyor', note: '' }); say('Kayıt kaydedildi.'); }
  function editFinance(key, mode, row) { setFinanceMode(mode); setEditing({ key, id: row.id }); setFinance({ title: row.title || '', amount: String(row.amount || ''), paid: String(row.paid || ''), date: (row.date || today()).slice(0, 10), dueDate: row.dueDate || '', category: row.category || categoryMap[mode][0], status: row.status || 'Devam ediyor', note: row.note || '' }); }
  function addDebtPayment(id) { const value = num(payment[id]); if (!value) return say('Ödeme tutarı gir.'); save({ ...data, debts: data.debts.map((d) => { if (d.id !== id) return d; const paid = Math.min(num(d.amount), num(d.paid) + value); return { ...d, paid, status: paid >= num(d.amount) ? 'Bitti' : paid > 0 ? 'Azaldı' : d.status }; }) }); setPayment({ ...payment, [id]: '' }); say('Borç ödemesi işlendi.'); }
  function addOrUpdateBudget() { if (!budget.name.trim()) return say('Kategori adı gir.'); const row = { id: editing?.id || uid(), name: budget.name.trim(), estimate: num(budget.estimate), actual: num(budget.actual), note: budget.note || '' }; save({ ...data, budgetCategories: editing?.key === 'budgetCategories' ? data.budgetCategories.map((x) => x.id === editing.id ? row : x) : [row, ...data.budgetCategories] }); setEditing(null); setBudget({ name: '', estimate: '', actual: '', note: '' }); say('Bütçe kategorisi kaydedildi.'); }
  function editBudget(row) { setEditing({ key: 'budgetCategories', id: row.id }); setBudget({ name: row.name, estimate: String(row.estimate || ''), actual: String(row.actual || ''), note: row.note || '' }); }
  function addOrUpdateItem() { if (!item.name.trim() || !num(item.estimate)) return say('Ürün adı ve fiyat gir.'); const row = { id: editing?.id || uid(), ...item, estimate: num(item.estimate), actual: num(item.actual), status: editing?.itemStatus || 'Planlandı' }; save({ ...data, items: editing?.key === 'items' ? data.items.map((x) => x.id === editing.id ? row : x) : [row, ...data.items] }); setEditing(null); setItem({ name: '', category: itemCategories[0], estimate: '', actual: '', priority: 'Orta', note: '' }); say('Ürün kaydedildi.'); }
  function editItem(row) { setEditing({ key: 'items', id: row.id, itemStatus: row.status }); setItem({ name: row.name, category: row.category, estimate: String(row.estimate || ''), actual: String(row.actual || ''), priority: row.priority || 'Orta', note: row.note || '' }); }
  function addHouse() { if (!house.title.trim() || !num(house.rent)) return say('Ev başlığı ve kira gir.'); save({ ...data, houses: [{ id: uid(), ...house, rent: num(house.rent), deposit: num(house.deposit), buildingAge: num(house.buildingAge), favorite: false }, ...data.houses] }); setHouse({ title: '', region: REGIONS[0], rent: '', deposit: '', buildingAge: '', note: '' }); say('Ev adayı eklendi.'); }
  function addSchool() { if (!school.name.trim() || !num(school.monthly)) return say('Okul adı ve ücret gir.'); save({ ...data, schools: [{ id: uid(), ...school, monthly: num(school.monthly), favorite: false }, ...data.schools] }); setSchool({ name: '', region: REGIONS[0], monthly: '', ageGroup: '5 yaş', note: '' }); say('Okul adayı eklendi.'); }
  function addTask() { if (!task.trim()) return say('Görev yaz.'); save({ ...data, checklist: [{ id: uid(), title: task.trim(), done: false }, ...data.checklist] }); setTask(''); }
  function addActivity() { if (!activity.trim()) return say('Aktivite yaz.'); save({ ...data, activities: [{ id: uid(), title: activity.trim(), done: false }, ...data.activities] }); setActivity(''); }
  function addOrUpdateNote() { if (!note.title.trim() || !note.body.trim()) return say('Not başlığı ve içerik gir.'); const row = { id: editing?.id || uid(), ...note, date: editing?.date || new Date().toISOString() }; save({ ...data, notes: editing?.key === 'notes' ? data.notes.map((x) => x.id === editing.id ? row : x) : [row, ...data.notes] }); setEditing(null); setNote({ title: '', category: noteCategories[0], body: '' }); say('Not kaydedildi.'); }
  function editNote(row) { setEditing({ key: 'notes', id: row.id, date: row.date }); setNote({ title: row.title, category: row.category || noteCategories[0], body: row.body || '' }); }
  function remove(key, id) { save({ ...data, [key]: data[key].filter((x) => x.id !== id) }); say('Silindi.'); }
  function makeBackup() { setBackup(JSON.stringify({ ...data, version: VERSION, exportedAt: new Date().toISOString() }, null, 2)); say('JSON yedeği hazır.'); }
  function restoreBackup() { try { save(merge(JSON.parse(backup))); say('Yedek geri yüklendi.'); } catch { say('Yedek okunamadı.'); } }

  return <View style={[styles.root, { backgroundColor: theme.bg }]}><StatusBar barStyle={theme.status} /><LinearGradient colors={theme.bgGradient} style={StyleSheet.absoluteFillObject} /><Background float={float} /><Header theme={theme} /><Animated.View style={[styles.flex, { opacity: fade }]}>{tab === 'panel' && <Dashboard theme={theme} data={data} stats={stats} />}{tab === 'finans' && <Finance theme={theme} data={data} mode={financeMode} setMode={switchFinanceMode} form={finance} setForm={setFinance} add={addOrUpdateFinance} editing={editing} editFinance={editFinance} payment={payment} setPayment={setPayment} addDebtPayment={addDebtPayment} remove={remove} stats={stats} />}{tab === 'butce' && <BudgetCenter theme={theme} data={data} save={save} stats={stats} tab={budgetTab} setTab={setBudgetTab} budget={budget} setBudget={setBudget} addBudget={addOrUpdateBudget} editBudget={editBudget} item={item} setItem={setItem} addItem={addOrUpdateItem} editItem={editItem} editing={editing} remove={remove} />}{tab === 'antalya' && <Antalya theme={theme} data={data} save={save} lifeTab={lifeTab} setLifeTab={setLifeTab} house={house} setHouse={setHouse} addHouse={addHouse} school={school} setSchool={setSchool} addSchool={addSchool} task={task} setTask={setTask} addTask={addTask} activity={activity} setActivity={setActivity} addActivity={addActivity} note={note} setNote={setNote} addNote={addOrUpdateNote} editNote={editNote} editing={editing} remove={remove} stats={stats} />}{tab === 'ayar' && <Settings theme={theme} data={data} save={save} backup={backup} setBackup={setBackup} makeBackup={makeBackup} restoreBackup={restoreBackup} reset={() => { save(emptyData); say('Tüm veriler sıfırlandı.'); }} />}</Animated.View>{!!toast && <Pressable onPress={() => setToast('')} style={styles.toast}><LinearGradient colors={['#2E6BFF', '#8A5CFF']} style={styles.toastInner}><Text style={styles.toastText}>{toast}</Text></LinearGradient></Pressable>}<Nav theme={theme} active={tab} setActive={setTab} /></View>;
}

function merge(raw) { return { ...emptyData, ...raw, settings: { ...emptyData.settings, ...(raw.settings || {}) }, motorcycle: { ...emptyData.motorcycle, ...(raw.motorcycle || {}), price: raw.motorcycle?.price ?? raw.settings?.motorcycleTarget ?? emptyData.motorcycle.price }, gtaGoal: { ...emptyData.gtaGoal, ...(raw.gtaGoal || {}), items: Array.isArray(raw.gtaGoal?.items) ? raw.gtaGoal.items : emptyData.gtaGoal.items }, relocation: { ...emptyData.relocation, ...(raw.relocation || {}) }, family: { ...emptyData.family, ...(raw.family || {}) }, budgetCategories: Array.isArray(raw.budgetCategories) ? raw.budgetCategories : makeBudgets(), incomes: Array.isArray(raw.incomes) ? raw.incomes : [], expenses: Array.isArray(raw.expenses) ? raw.expenses : [], savings: Array.isArray(raw.savings) ? raw.savings : [], debts: Array.isArray(raw.debts) ? raw.debts : [], items: Array.isArray(raw.items) ? raw.items : [], houses: Array.isArray(raw.houses) ? raw.houses : [], schools: Array.isArray(raw.schools) ? raw.schools : [], checklist: Array.isArray(raw.checklist) ? raw.checklist : [], notes: Array.isArray(raw.notes) ? raw.notes : [], activities: Array.isArray(raw.activities) ? raw.activities : [] }; }
function getStats(data) { const budgetEstimate = sum(data.budgetCategories, 'estimate'); const budgetActual = sum(data.budgetCategories, 'actual'); const income = sum(data.incomes); const expense = sum(data.expenses); const saving = sum(data.savings) + num(data.motorcycle.saved); const debtTotal = sum(data.debts); const debtPaid = sum(data.debts, 'paid'); const target = budgetEstimate || num(data.settings.targetBudget); const days = daysLeft(data.settings.targetDate); const gtaDays = daysLeft(data.gtaGoal.targetDate); const left = Math.max(0, target - saving); const daily = days > 0 ? Math.ceil(left / days) : left; const itemsTotal = data.items.reduce((s, x) => s + num(x.actual || x.estimate), 0); const boughtTotal = data.items.filter((x) => ['Satın Alındı', 'Kuruldu'].includes(x.status)).reduce((s, x) => s + num(x.actual || x.estimate), 0); const boughtCount = data.items.filter((x) => ['Satın Alındı', 'Kuruldu'].includes(x.status)).length; const gtaTotal = data.gtaGoal.items.reduce((s, x) => s + num(x.cost), 0); const gtaReady = data.gtaGoal.items.filter((x) => ['Satın Alındı', 'Kuruldu'].includes(x.status)).length; const doneTasks = data.checklist.filter((x) => x.done).length; const monthSavings = data.savings.filter((x) => sameMonth(x.date)).reduce((s, x) => s + num(x.amount), 0); return { budgetEstimate, budgetActual, budgetDiff: budgetEstimate - budgetActual, income, expense, saving, net: income - expense, target, days, gtaDays, left, progress: pct(saving, target), daily, weekly: daily * 7, monthly: daily * 30, todayIncome: data.incomes.filter((x) => sameDay(x.date)).reduce((s, x) => s + num(x.amount), 0), todayExpense: data.expenses.filter((x) => sameDay(x.date)).reduce((s, x) => s + num(x.amount), 0), weekIncome: data.incomes.filter((x) => last7(x.date)).reduce((s, x) => s + num(x.amount), 0), weekExpense: data.expenses.filter((x) => last7(x.date)).reduce((s, x) => s + num(x.amount), 0), monthIncome: data.incomes.filter((x) => sameMonth(x.date)).reduce((s, x) => s + num(x.amount), 0), monthExpense: data.expenses.filter((x) => sameMonth(x.date)).reduce((s, x) => s + num(x.amount), 0), monthSavings, debtTotal, debtPaid, debtLeft: Math.max(0, debtTotal - debtPaid), debtPct: pct(debtPaid, debtTotal), itemsTotal, boughtTotal, itemsLeft: Math.max(0, itemsTotal - boughtTotal), boughtCount, doneTasks, taskPct: pct(doneTasks, data.checklist.length), motorcycleLeft: Math.max(0, num(data.motorcycle.price) - num(data.motorcycle.saved)), gtaTotal, gtaReady }; }
function getTheme(mode) { if (mode === 'light') return { mode, status: 'dark-content', bg: '#F6F8FF', bgGradient: ['#F7FAFF', '#ECF4FF', '#FFF6F1'], card: 'rgba(255,255,255,0.92)', card2: '#FFFFFF', text: '#111827', muted: '#667085', line: 'rgba(16,24,40,0.10)', nav: 'rgba(255,255,255,0.95)' }; return { mode, status: 'light-content', bg: '#08111F', bgGradient: ['#08111F', '#10264A', '#1A1238'], card: 'rgba(255,255,255,0.118)', card2: 'rgba(255,255,255,0.075)', text: '#FFFFFF', muted: '#C4D0E3', line: 'rgba(255,255,255,0.14)', nav: 'rgba(10,21,38,0.94)' }; }
function groupSum(list, key) { const out = {}; list.forEach((x) => { const k = x.category || 'Diğer'; out[k] = (out[k] || 0) + num(x[key] || x.amount || x.estimate || x.cost); }); return Object.entries(out).sort((a, b) => b[1] - a[1]); }

function Background({ float }) { const y = float.interpolate({ inputRange: [0, 1], outputRange: [0, -22] }); return <View pointerEvents="none" style={StyleSheet.absoluteFillObject}><Animated.View style={[styles.blobOne, { transform: [{ translateY: y }] }]} /><Animated.View style={[styles.blobTwo, { transform: [{ translateY: y }] }]} /><Animated.View style={[styles.blobThree, { transform: [{ translateY: y }] }]} /></View>; }
function Header({ theme }) { return <View style={styles.header}><View style={styles.brand}><LinearGradient colors={['#2EE6A6', '#2E6BFF']} style={styles.logo}><MaterialCommunityIcons name="palm-tree" size={26} color="white" /></LinearGradient><View><Text style={[styles.appTitle, { color: theme.text }]}>DraBornLife</Text><Text style={[styles.appSub, { color: theme.muted }]}>v0.2 Antalya panel</Text></View></View><View style={styles.version}><Text style={styles.versionText}>{VERSION}</Text></View></View>; }
function Dashboard({ theme, data, stats }) { return <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}><LinearGradient colors={['#0FE0A0', '#2E6BFF', '#8A5CFF']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }} style={styles.hero}><Text style={styles.heroKicker}>ANTALYA HAZIRLIK • EKİM SONU 2026</Text><Text style={styles.heroPercent}>%{stats.progress}</Text><Text style={styles.heroText}>{stats.days} gün kaldı. Taşınma bütçesi, aile planı ve hedefler tek panelde.</Text><Bar value={stats.progress} /><View style={styles.heroStats}><Mini label="Hedef" value={money(stats.target)} /><Mini label="Birikim" value={money(stats.saving)} /><Mini label="Eksik" value={money(stats.left)} /></View></LinearGradient><LinearGradient colors={['#FF4D8D', '#8A5CFF', '#2E6BFF']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }} style={styles.gtaCard}><View><Text style={styles.gtaKicker}>GTA 6 GERİ SAYIM</Text><Text style={styles.gtaDays}>{stats.gtaDays}</Text><Text style={styles.gtaLabel}>gün kaldı</Text></View><View style={styles.gtaIcon}><MaterialCommunityIcons name="gamepad-variant" size={46} color="white" /></View><Text style={styles.gtaText}>19 Kasım 2026’dan önce ev, TV ve PS5 Pro seti hazır olmalı.</Text></LinearGradient><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Bugünkü durum</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>Bugün gelir: {money(stats.todayIncome)} • Bugün gider: {money(stats.todayExpense)}{`\n`}Bu ay hedefe yaklaşılan tutar: {money(stats.monthSavings)}{`\n`}Günlük: {money(stats.daily)} • Haftalık: {money(stats.weekly)} • Aylık: {money(stats.monthly)}</Text></Card><PanelReports theme={theme} data={data} stats={stats} /><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Yeni hayat hedefi</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>{data.family.note}{`\n`}{data.family.motivation}</Text></Card></ScrollView>; }
function PanelReports({ theme, data, stats }) { const itemGroups = groupSum(data.items.map((x) => ({ category: x.category, amount: x.actual || x.estimate }))); const expenseGroups = groupSum(data.expenses); return <><Title theme={theme} title="Panel Raporları" sub="Kategoriler ve aylık özet" /><View style={styles.metricGrid}><Metric colors={['#2E6BFF', '#31B5FF']} icon="calendar-month" label="Aylık gelir" value={money(stats.monthIncome)} /><Metric colors={['#FF4D8D', '#FF9E2C']} icon="calendar-month" label="Aylık gider" value={money(stats.monthExpense)} /><Metric colors={['#0FE0A0', '#27D3C3']} icon="target" label="Hedefe kalan" value={money(stats.left)} /><Metric colors={['#8A5CFF', '#FF4D6D']} icon="chart-bar" label="Hazırlık" value={`%${stats.taskPct}`} /></View><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Alınacaklar kategori raporu</Text>{itemGroups.length === 0 ? <Text style={[styles.bodyBig, { color: theme.muted }]}>Henüz alınacak eklenmedi.</Text> : itemGroups.map(([k, v]) => <Text key={k} style={[styles.bodyBig, { color: theme.muted }]}>{k}: {money(v)}</Text>)}</Card><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Gider kategori raporu</Text>{expenseGroups.length === 0 ? <Text style={[styles.bodyBig, { color: theme.muted }]}>Henüz gider eklenmedi.</Text> : expenseGroups.map(([k, v]) => <Text key={k} style={[styles.bodyBig, { color: theme.muted }]}>{k}: {money(v)}</Text>)}</Card></>; }
function Finance({ theme, data, mode, setMode, form, setForm, add, editing, editFinance, payment, setPayment, addDebtPayment, remove, stats }) { const key = mode === 'income' ? 'incomes' : mode === 'expense' ? 'expenses' : mode === 'saving' ? 'savings' : 'debts'; const active = financeModes.find((x) => x[0] === mode) || financeModes[0]; const list = data[key]; return <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}><Title theme={theme} title="Finans" sub="Modern kategori listesiyle kayıt ekle" /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.modeRow}>{financeModes.map(([id, label, icon, colors]) => <Mode key={id} active={mode === id} label={label} icon={icon} colors={colors} onPress={() => setMode(id)} />)}</ScrollView><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>{editing?.key === key ? 'Kaydı düzenle' : `${active[1]} ekle`}</Text><Text style={[styles.sectionHint, { color: theme.muted }]}>Kategori seç</Text><CategoryList theme={theme} mode={mode} selected={form.category} onSelect={(category) => setForm({ ...form, category })} /><Input theme={theme} label={mode === 'debt' ? 'Borç adı' : 'Başlık'} value={form.title} onChangeText={(v) => setForm({ ...form, title: v })} /><Input theme={theme} label="Tutar" value={form.amount} keyboardType="numeric" onChangeText={(v) => setForm({ ...form, amount: v })} /><Input theme={theme} label="Tarih YYYY-MM-DD" value={form.date} onChangeText={(v) => setForm({ ...form, date: v })} /><Input theme={theme} label="Manuel kategori" value={form.category} onChangeText={(v) => setForm({ ...form, category: v })} />{mode === 'debt' && <><Input theme={theme} label="Ödenen tutar" value={form.paid} keyboardType="numeric" onChangeText={(v) => setForm({ ...form, paid: v })} /><Input theme={theme} label="Son ödeme tarihi" value={form.dueDate} onChangeText={(v) => setForm({ ...form, dueDate: v })} /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{debtStatuses.map((s) => <Pill key={s} theme={theme} active={form.status === s} label={s} onPress={() => setForm({ ...form, status: s })} />)}</ScrollView></>}<Input theme={theme} label="Not" value={form.note} onChangeText={(v) => setForm({ ...form, note: v })} /><Button label="Kaydet" colors={active[3]} onPress={add} /></Card><View style={styles.metricGrid}><Metric colors={['#2E6BFF', '#31B5FF']} icon="calendar-today" label="Bugün" value={money(mode === 'income' ? stats.todayIncome : mode === 'expense' ? stats.todayExpense : 0)} /><Metric colors={['#0FE0A0', '#27D3C3']} icon="calendar-week" label="7 gün" value={money(mode === 'income' ? stats.weekIncome : mode === 'expense' ? stats.weekExpense : stats.weekly)} /><Metric colors={['#FF9E2C', '#FF4D8D']} icon="calendar-month" label="Bu ay" value={money(mode === 'income' ? stats.monthIncome : mode === 'expense' ? stats.monthExpense : stats.monthSavings)} /><Metric colors={['#8A5CFF', '#FF4D6D']} icon="chart-bar" label="Genel" value={money(mode === 'income' ? stats.income : mode === 'expense' ? stats.expense : mode === 'saving' ? stats.saving : stats.debtLeft)} /></View>{mode === 'debt' && <Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Borç barı</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>Toplam {money(stats.debtTotal)} • Ödenen {money(stats.debtPaid)} • Kalan {money(stats.debtLeft)}</Text><Bar value={stats.debtPct} /></Card>}{list.length === 0 && <Empty theme={theme} icon="playlist-plus" text="Henüz kayıt yok." />}{list.map((x) => mode === 'debt' ? <Debt key={x.id} theme={theme} debt={x} payment={payment} setPayment={setPayment} addDebtPayment={addDebtPayment} onEdit={() => editFinance('debts', 'debt', x)} onDelete={() => remove('debts', x.id)} /> : <Record key={x.id} theme={theme} title={x.title} sub={`${x.category || 'Genel'} • ${(x.date || '').slice(0, 10)}`} value={money(x.amount)} note={x.note} onEdit={() => editFinance(key, mode, x)} onDelete={() => remove(key, x.id)} />)}</ScrollView>; }
function CategoryList({ theme, mode, selected, onSelect }) { const colors = (financeModes.find((x) => x[0] === mode) || financeModes[0])[3]; return <View style={styles.categoryList}>{categoryMap[mode].map((category) => { const active = selected === category; return <Pressable key={category} onPress={() => onSelect(category)} style={[styles.categoryRow, { backgroundColor: active ? 'rgba(49,181,255,0.18)' : theme.card2, borderColor: active ? '#31B5FF' : theme.line }]}><LinearGradient colors={active ? colors : ['rgba(255,255,255,0.14)', 'rgba(255,255,255,0.08)']} style={styles.categoryIcon}><MaterialCommunityIcons name={catIcons[category] || 'dots-horizontal-circle'} size={24} color="white" /></LinearGradient><View style={styles.flex}><Text style={[styles.categoryTitle, { color: active ? '#31B5FF' : theme.text }]}>{category}</Text><Text style={[styles.categorySub, { color: theme.muted }]}>{active ? 'Seçili kategori' : 'Dokun ve seç'}</Text></View>{active ? <MaterialCommunityIcons name="check-circle" size={24} color="#31B5FF" /> : <MaterialCommunityIcons name="chevron-right" size={24} color={theme.muted} />}</Pressable>; })}</View>; }
function Debt({ theme, debt, payment, setPayment, addDebtPayment, onEdit, onDelete }) { const done = pct(num(debt.paid), num(debt.amount)); return <Card theme={theme}><View style={styles.rowTop}><View style={styles.flex}><Text style={[styles.itemTitle, { color: theme.text }]}>{debt.title}</Text><Text style={[styles.itemSub, { color: theme.muted }]}>{debt.status} • Son ödeme: {debt.dueDate || 'Yok'} • Kalan {money(num(debt.amount) - num(debt.paid))}</Text></View><Text style={[styles.itemValue, { color: theme.text }]}>{money(debt.amount)}</Text></View><Bar value={done} /><Input theme={theme} label="Ödeme ekle" value={payment[debt.id] || ''} keyboardType="numeric" onChangeText={(v) => setPayment({ ...payment, [debt.id]: v })} /><Button label="Ödeme işle" colors={['#0FE0A0', '#2E6BFF']} onPress={() => addDebtPayment(debt.id)} /><Actions onEdit={onEdit} onDelete={onDelete} /></Card>; }
function BudgetCenter(props) { const tabs = [['budget', 'Bütçe', 'calculator'], ['items', 'Alınacaklar', 'cart'], ['motor', 'Motor', 'motorbike'], ['gta', 'GTA 6', 'gamepad-variant']]; return <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}><Title theme={props.theme} title="Bütçe & Hedefler" sub="Kategori bütçesi, alınacaklar, motor ve GTA seti" /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.modeRow}>{tabs.map(([id, label, icon]) => <Mode key={id} active={props.tab === id} label={label} icon={icon} colors={['#0FE0A0', '#2E6BFF']} onPress={() => props.setTab(id)} />)}</ScrollView>{props.tab === 'budget' && <BudgetCategories {...props} />}{props.tab === 'items' && <Shopping {...props} />}{props.tab === 'motor' && <MotorGoal {...props} />}{props.tab === 'gta' && <GtaGoal {...props} />}</ScrollView>; }
function BudgetCategories({ theme, data, stats, budget, setBudget, addBudget, editBudget, remove }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Hedef bütçe kategorisi</Text><Input theme={theme} label="Kategori" value={budget.name} onChangeText={(v) => setBudget({ ...budget, name: v })} /><Input theme={theme} label="Tahmini tutar" value={budget.estimate} keyboardType="numeric" onChangeText={(v) => setBudget({ ...budget, estimate: v })} /><Input theme={theme} label="Gerçekleşen tutar" value={budget.actual} keyboardType="numeric" onChangeText={(v) => setBudget({ ...budget, actual: v })} /><Input theme={theme} label="Not" value={budget.note} onChangeText={(v) => setBudget({ ...budget, note: v })} /><Button label="Kategori kaydet" colors={['#0FE0A0', '#2E6BFF']} onPress={addBudget} /></Card><View style={styles.metricGrid}><Metric colors={['#2E6BFF', '#31B5FF']} icon="calculator" label="Tahmini" value={money(stats.budgetEstimate)} /><Metric colors={['#FF9E2C', '#FF4D8D']} icon="check" label="Gerçekleşen" value={money(stats.budgetActual)} /></View>{data.budgetCategories.map((b) => <Record key={b.id} theme={theme} title={b.name} sub={`Tahmini ${money(b.estimate)} • Gerçek ${money(b.actual)}`} value={money(num(b.estimate) - num(b.actual))} note={b.note} onEdit={() => editBudget(b)} onDelete={() => remove('budgetCategories', b.id)} />)}</>; }
function Shopping({ theme, data, item, setItem, addItem, editItem, remove, save, stats }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Alınacak ürün</Text><Input theme={theme} label="Ürün adı" value={item.name} onChangeText={(v) => setItem({ ...item, name: v })} /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{itemCategories.map((cat) => <Pill key={cat} theme={theme} active={item.category === cat} label={cat} onPress={() => setItem({ ...item, category: cat })} />)}</ScrollView><Input theme={theme} label="Tahmini fiyat" value={item.estimate} keyboardType="numeric" onChangeText={(v) => setItem({ ...item, estimate: v })} /><Input theme={theme} label="Gerçek fiyat" value={item.actual} keyboardType="numeric" onChangeText={(v) => setItem({ ...item, actual: v })} /><Input theme={theme} label="Öncelik" value={item.priority} onChangeText={(v) => setItem({ ...item, priority: v })} /><Input theme={theme} label="Not" value={item.note} onChangeText={(v) => setItem({ ...item, note: v })} /><Button label="Ürün kaydet" colors={['#FF9E2C', '#FF4D8D']} onPress={addItem} /></Card><View style={styles.metricGrid}><Metric colors={['#FF9E2C', '#FF4D8D']} icon="calculator" label="Toplam" value={money(stats.itemsTotal)} /><Metric colors={['#0FE0A0', '#2E6BFF']} icon="check-circle" label="Alınan TL" value={money(stats.boughtTotal)} /><Metric colors={['#8B5CF6', '#2E6BFF']} icon="cart" label="Kalan" value={money(stats.itemsLeft)} /><Metric colors={['#2E6BFF', '#31B5FF']} icon="format-list-checks" label="Adet" value={`${stats.boughtCount}/${data.items.length}`} /></View>{data.items.length === 0 && <Empty theme={theme} icon="cart-plus" text="Alınacaklar boş." />}{data.items.map((x) => <Card key={x.id} theme={theme}><View style={styles.rowTop}><BadgeIcon icon="cart" colors={['#FF9E2C', '#FF4D8D']} /><View style={styles.flex}><Text style={[styles.itemTitle, { color: theme.text }]}>{x.name}</Text><Text style={[styles.itemSub, { color: theme.muted }]}>{x.category} • {x.priority}</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>{x.note}</Text></View><Text style={[styles.itemValue, { color: theme.text }]}>{money(x.actual || x.estimate)}</Text></View><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{itemStatuses.map((s) => <Pill key={s} theme={theme} active={x.status === s} label={s} onPress={() => save({ ...data, items: data.items.map((i) => i.id === x.id ? { ...i, status: s } : i) })} />)}</ScrollView><Actions onEdit={() => editItem(x)} onDelete={() => remove('items', x.id)} /></Card>)}</>; }
function MotorGoal({ theme, data, save, stats }) { const m = data.motorcycle; return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Yeni motosiklet hedefi</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>Varsayılan hedef 130.000 TL. Eski motosiklet satılacak, Antalya’da sıfır motosiklet alınacak.</Text><Input theme={theme} label="Hedef fiyat" value={String(m.price)} keyboardType="numeric" onChangeText={(v) => save({ ...data, motorcycle: { ...m, price: num(v) } })} /><Input theme={theme} label="Birikmiş tutar" value={String(m.saved)} keyboardType="numeric" onChangeText={(v) => save({ ...data, motorcycle: { ...m, saved: num(v) } })} /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{motoStatuses.map((s) => <Pill key={s} theme={theme} active={m.status === s} label={s} onPress={() => save({ ...data, motorcycle: { ...m, status: s } })} />)}</ScrollView><Input theme={theme} label="Not" value={m.note} onChangeText={(v) => save({ ...data, motorcycle: { ...m, note: v } })} /><Bar value={pct(m.saved, m.price)} /></Card><View style={styles.metricGrid}><Metric colors={['#2E6BFF', '#31B5FF']} icon="motorbike" label="Hedef" value={money(m.price)} /><Metric colors={['#0FE0A0', '#27D3C3']} icon="piggy-bank" label="Kalan" value={money(stats.motorcycleLeft)} /></View></>; }
function GtaGoal({ theme, data, save, stats }) { const g = data.gtaGoal; const update = (id, patch) => save({ ...data, gtaGoal: { ...g, items: g.items.map((x) => x.id === id ? { ...x, ...patch } : x) } }); const addToItems = (x) => save({ ...data, items: [{ id: uid(), name: x.name, category: x.name.includes('TV') ? 'TV' : x.name.includes('PS5') ? 'PS5 Pro' : 'GTA 6 seti', estimate: num(x.cost), actual: 0, priority: 'Orta', note: 'GTA 6 setinden eklendi.', status: x.status }, ...data.items] }); return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>GTA 6 / PS5 Pro / TV hedefi</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>19 Kasım 2026’dan önce hazır olmalı. Kalan gün: {stats.gtaDays}. Toplam set maliyeti: {money(stats.gtaTotal)}</Text><Input theme={theme} label="Hedef notu" value={g.note} onChangeText={(v) => save({ ...data, gtaGoal: { ...g, note: v } })} /></Card>{g.items.map((x) => <Card key={x.id} theme={theme}><View style={styles.rowTop}><BadgeIcon icon={x.name.includes('TV') ? 'television' : 'gamepad-variant'} colors={['#8A5CFF', '#2E6BFF']} /><View style={styles.flex}><Text style={[styles.itemTitle, { color: theme.text }]}>{x.name}</Text><Input theme={theme} label="Tahmini fiyat" value={String(x.cost)} keyboardType="numeric" onChangeText={(v) => update(x.id, { cost: num(v) })} /></View></View><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{itemStatuses.filter((s) => s !== 'Vazgeçildi').map((s) => <Pill key={s} theme={theme} active={x.status === s} label={s} onPress={() => update(x.id, { status: s })} />)}</ScrollView><Button label="Alınacaklar listesine ekle" colors={['#8A5CFF', '#2E6BFF']} onPress={() => addToItems(x)} /></Card>)}</>; }
function Antalya({ theme, data, save, lifeTab, setLifeTab, house, setHouse, addHouse, school, setSchool, addSchool, task, setTask, addTask, activity, setActivity, addActivity, note, setNote, addNote, editNote, editing, remove, stats }) { const tabs = [['plan', 'Plan', 'map-marker'], ['ev', 'Evler', 'home'], ['okul', 'Okullar', 'school'], ['check', 'Checklist', 'clipboard-check'], ['aile', 'Aile', 'heart'], ['not', 'Notlar', 'note-text']]; return <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}><Title theme={theme} title="Antalya Planı" sub="Ev, okul, checklist ve aile motivasyonu" /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.modeRow}>{tabs.map(([id, label, icon]) => <Mode key={id} active={lifeTab === id} label={label} icon={icon} colors={['#0FE0A0', '#2E6BFF']} onPress={() => setLifeTab(id)} />)}</ScrollView>{lifeTab === 'plan' && <MovePlan theme={theme} data={data} save={save} stats={stats} />}{lifeTab === 'ev' && <Houses theme={theme} houses={data.houses} house={house} setHouse={setHouse} addHouse={addHouse} save={save} data={data} remove={remove} />}{lifeTab === 'okul' && <Schools theme={theme} schools={data.schools} school={school} setSchool={setSchool} addSchool={addSchool} save={save} data={data} remove={remove} />}{lifeTab === 'check' && <Checklist theme={theme} data={data} save={save} task={task} setTask={setTask} addTask={addTask} remove={remove} />}{lifeTab === 'aile' && <Family theme={theme} data={data} save={save} activity={activity} setActivity={setActivity} addActivity={addActivity} remove={remove} />}{lifeTab === 'not' && <Notes theme={theme} notes={data.notes} note={note} setNote={setNote} addNote={addNote} editNote={editNote} editing={editing} remove={remove} />}</ScrollView>; }
function MovePlan({ theme, data, save, stats }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Hedef şehir: Antalya</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>Öncelikli bölgeler: {data.relocation.regions}{`\n`}Hedef: {data.relocation.homeGoal}{`\n`}{data.relocation.moveNote}</Text><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{moveStatuses.map((s) => <Pill key={s} theme={theme} active={data.relocation.status === s} label={s} onPress={() => save({ ...data, relocation: { ...data.relocation, status: s } })} />)}</ScrollView></Card><Metric colors={['#0FE0A0', '#2E6BFF']} icon="clipboard-check" label="Taşınma hazırlık yüzdesi" value={`%${stats.taskPct}`} /></>; }
function Houses({ theme, houses, house, setHouse, addHouse, save, data, remove }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Ev adayı ekle</Text><Input theme={theme} label="Ev başlığı" value={house.title} onChangeText={(v) => setHouse({ ...house, title: v })} /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{REGIONS.map((r) => <Pill key={r} theme={theme} active={house.region === r} label={r} onPress={() => setHouse({ ...house, region: r })} />)}</ScrollView><Input theme={theme} label="Kira" value={house.rent} keyboardType="numeric" onChangeText={(v) => setHouse({ ...house, rent: v })} /><Input theme={theme} label="Depozito" value={house.deposit} keyboardType="numeric" onChangeText={(v) => setHouse({ ...house, deposit: v })} /><Input theme={theme} label="Bina yaşı" value={house.buildingAge} keyboardType="numeric" onChangeText={(v) => setHouse({ ...house, buildingAge: v })} /><Input theme={theme} label="Not" value={house.note} onChangeText={(v) => setHouse({ ...house, note: v })} /><Button label="Ev kaydet" colors={['#2E6BFF', '#31B5FF']} onPress={addHouse} /></Card>{houses.length === 0 && <Empty theme={theme} icon="home-plus" text="Ev listesi boş." />}{houses.map((h) => <Record key={h.id} theme={theme} title={`${h.favorite ? '★ ' : ''}${h.title}`} sub={`${h.region || 'Bölge yok'} • Bina ${h.buildingAge || 0} yaş`} value={money(h.rent)} note={h.note} onEdit={() => save({ ...data, houses: data.houses.map((x) => x.id === h.id ? { ...x, favorite: !x.favorite } : x) })} onDelete={() => remove('houses', h.id)} />)}</>; }
function Schools({ theme, schools, school, setSchool, addSchool, save, data, remove }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Okul adayı ekle</Text><Input theme={theme} label="Okul adı" value={school.name} onChangeText={(v) => setSchool({ ...school, name: v })} /><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{REGIONS.map((r) => <Pill key={r} theme={theme} active={school.region === r} label={r} onPress={() => setSchool({ ...school, region: r })} />)}</ScrollView><Input theme={theme} label="Aylık ücret" value={school.monthly} keyboardType="numeric" onChangeText={(v) => setSchool({ ...school, monthly: v })} /><Input theme={theme} label="Yaş grubu" value={school.ageGroup} onChangeText={(v) => setSchool({ ...school, ageGroup: v })} /><Input theme={theme} label="Not" value={school.note} onChangeText={(v) => setSchool({ ...school, note: v })} /><Button label="Okul kaydet" colors={['#0FE0A0', '#2E6BFF']} onPress={addSchool} /></Card>{schools.length === 0 && <Empty theme={theme} icon="school" text="Okul listesi boş." />}{schools.map((s) => <Record key={s.id} theme={theme} title={`${s.favorite ? '★ ' : ''}${s.name}`} sub={`${s.region || 'Bölge yok'} • ${s.ageGroup}`} value={money(s.monthly)} note={s.note} onEdit={() => save({ ...data, schools: data.schools.map((x) => x.id === s.id ? { ...x, favorite: !x.favorite } : x) })} onDelete={() => remove('schools', s.id)} />)}</>; }
function Checklist({ theme, data, save, task, setTask, addTask, remove }) { const done = data.checklist.filter((x) => x.done).length; return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Taşınma checklist</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>{done}/{data.checklist.length} görev tamamlandı.</Text><Bar value={pct(done, data.checklist.length)} /><Input theme={theme} label="Yeni görev" value={task} onChangeText={setTask} /><Button label="Görev ekle" colors={['#8A5CFF', '#2E6BFF']} onPress={addTask} /></Card>{data.checklist.length === 0 && <Empty theme={theme} icon="clipboard-plus" text="Checklist boş." />}{data.checklist.map((x) => <Card key={x.id} theme={theme}><Pressable onPress={() => save({ ...data, checklist: data.checklist.map((i) => i.id === x.id ? { ...i, done: !i.done } : i) })} style={styles.rowTop}><MaterialCommunityIcons name={x.done ? 'check-circle' : 'circle-outline'} size={34} color={x.done ? '#0FE0A0' : theme.muted} /><View style={styles.flex}><Text style={[styles.itemTitle, { color: theme.text, textDecorationLine: x.done ? 'line-through' : 'none' }]}>{x.title}</Text></View></Pressable><Delete onPress={() => remove('checklist', x.id)} /></Card>)}</>; }
function Family({ theme, data, save, activity, setActivity, addActivity, remove }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Yeni Hayat Hedefi</Text><Input theme={theme} label="Aile motivasyon notu" value={data.family.note} onChangeText={(v) => save({ ...data, family: { ...data.family, note: v } })} /><Input theme={theme} label="Deniz / sahil / yeni yaşam notu" value={data.family.motivation} onChangeText={(v) => save({ ...data, family: { ...data.family, motivation: v } })} multiline /><Input theme={theme} label="Aktivite ekle" value={activity} onChangeText={setActivity} /><Button label="Aktivite ekle" colors={['#FF4D8D', '#2E6BFF']} onPress={addActivity} /></Card>{data.activities.length === 0 && <Empty theme={theme} icon="heart-plus" text="Aquapark, sahil, deniz, aile aktivitelerini buraya ekle." />}{data.activities.map((x) => <Card key={x.id} theme={theme}><Pressable onPress={() => save({ ...data, activities: data.activities.map((i) => i.id === x.id ? { ...i, done: !i.done } : i) })} style={styles.rowTop}><MaterialCommunityIcons name={x.done ? 'check-circle' : 'heart-outline'} size={32} color={x.done ? '#0FE0A0' : '#FF4D8D'} /><Text style={[styles.itemTitle, { color: theme.text }]}>{x.title}</Text></Pressable><Delete onPress={() => remove('activities', x.id)} /></Card>)}</>; }
function Notes({ theme, notes, note, setNote, addNote, editNote, editing, remove }) { return <><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>{editing?.key === 'notes' ? 'Notu düzenle' : 'Not ekle'}</Text><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.pillRow}>{noteCategories.map((cat) => <Pill key={cat} theme={theme} active={note.category === cat} label={cat} onPress={() => setNote({ ...note, category: cat })} />)}</ScrollView><Input theme={theme} label="Başlık" value={note.title} onChangeText={(v) => setNote({ ...note, title: v })} /><Input theme={theme} label="Not" value={note.body} onChangeText={(v) => setNote({ ...note, body: v })} multiline /><Button label="Notu kaydet" colors={['#FF4D8D', '#2E6BFF']} onPress={addNote} /></Card>{notes.length === 0 && <Empty theme={theme} icon="note-plus" text="Notlar boş." />}{notes.map((x) => <Record key={x.id} theme={theme} title={x.title} sub={`${x.category || 'Genel'} • ${new Date(x.date).toLocaleDateString('tr-TR')}`} note={x.body} onEdit={() => editNote(x)} onDelete={() => remove('notes', x.id)} />)}</>; }
function Settings({ theme, data, save, backup, setBackup, makeBackup, restoreBackup, reset }) { return <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}><Title theme={theme} title="Ayarlar" sub="Hedef, tema, yedek, hakkında" /><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Tema</Text><View style={styles.themeRow}><Button label="Koyu" colors={['#08111F', '#2E6BFF']} onPress={() => save({ ...data, settings: { ...data.settings, theme: 'dark' } })} /><Button label="Açık" colors={['#EAF2FF', '#B9D7FF']} onPress={() => save({ ...data, settings: { ...data.settings, theme: 'light' } })} /></View></Card><Card theme={theme}><Input theme={theme} label="Toplam hedef bütçe" value={String(data.settings.targetBudget)} keyboardType="numeric" onChangeText={(v) => save({ ...data, settings: { ...data.settings, targetBudget: num(v) } })} /><Input theme={theme} label="Hedef tarih" value={data.settings.targetDate} onChangeText={(v) => save({ ...data, settings: { ...data.settings, targetDate: v } })} /><Input theme={theme} label="Para birimi" value={data.settings.currency} onChangeText={(v) => save({ ...data, settings: { ...data.settings, currency: v || 'TL' } })} /></Card><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Yedekleme</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>Manuel JSON yedeği oluşturulur. Metni dosya olarak saklayabilir, başka telefonda içe aktarabilirsin.</Text><Button label="Yedek oluştur" colors={['#2E6BFF', '#8A5CFF']} onPress={makeBackup} /><Input theme={theme} label="Yedek JSON" value={backup} onChangeText={setBackup} multiline /><Button label="Geri yükle" colors={['#0FE0A0', '#2E6BFF']} onPress={restoreBackup} /></Card><Card theme={theme}><Text style={[styles.cardTitleBig, { color: theme.text }]}>Uygulama hakkında</Text><Text style={[styles.bodyBig, { color: theme.muted }]}>DraBornLife {VERSION}. APK hedefi v1.0. Supabase, web panel, login ve bulut senkron yok; veriler cihaz içinde saklanır.</Text><Pressable onPress={reset}><Text style={styles.deleteText}>Verileri sıfırla</Text></Pressable></Card></ScrollView>; }

function Title({ theme, title, sub }) { return <View style={styles.screenTitle}><Text style={[styles.screenText, { color: theme.text }]}>{title}</Text><Text style={[styles.screenSub, { color: theme.muted }]}>{sub}</Text></View>; }
function Card({ theme, children }) { return <View style={[styles.card, { backgroundColor: theme.card, borderColor: theme.line }]}>{children}</View>; }
function Input({ theme, label, multiline, ...props }) { return <View style={styles.field}><Text style={[styles.label, { color: theme.muted }]}>{label}</Text><TextInput placeholderTextColor="#8CA0BA" style={[styles.input, multiline && styles.multi, { color: theme.text, borderColor: theme.line, backgroundColor: theme.card2 }]} multiline={multiline} {...props} /></View>; }
function Button({ label, colors, onPress }) { return <Pressable onPress={onPress} style={styles.buttonWrap}><LinearGradient colors={colors} start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={styles.button}><Text style={styles.buttonText}>{label}</Text></LinearGradient></Pressable>; }
function Bar({ value }) { return <View style={styles.track}><LinearGradient colors={['#0FE0A0', '#2E6BFF', '#8A5CFF']} style={[styles.fill, { width: `${Math.max(4, value)}%` }]} /></View>; }
function Mini({ label, value }) { return <View><Text style={styles.miniLabel}>{label}</Text><Text style={styles.miniValue}>{value}</Text></View>; }
function Metric({ colors, icon, label, value }) { return <LinearGradient colors={colors} style={styles.metric}><MaterialCommunityIcons name={icon} size={28} color="white" /><Text numberOfLines={2} style={styles.metricValue}>{value}</Text><Text style={styles.metricLabel}>{label}</Text></LinearGradient>; }
function Mode({ active, label, icon, colors, onPress }) { return <Pressable onPress={onPress} style={styles.mode}><LinearGradient colors={active ? colors : ['rgba(255,255,255,0.12)', 'rgba(255,255,255,0.06)']} style={styles.modeInner}><MaterialCommunityIcons name={icon} size={26} color="white" /><Text style={styles.modeText}>{label}</Text></LinearGradient></Pressable>; }
function Pill({ theme, active, label, onPress }) { return <Pressable onPress={onPress} style={[styles.pill, { borderColor: active ? '#31B5FF' : theme.line, backgroundColor: active ? 'rgba(49,181,255,0.18)' : 'transparent' }]}><Text style={[styles.pillText, { color: active ? '#31B5FF' : theme.muted }]}>{label}</Text></Pressable>; }
function BadgeIcon({ icon, colors }) { return <LinearGradient colors={colors} style={styles.badgeIcon}><MaterialCommunityIcons name={icon} size={24} color="white" /></LinearGradient>; }
function Record({ theme, title, sub, value, note, onEdit, onDelete }) { return <Card theme={theme}><View style={styles.rowTop}><View style={styles.flex}><Text style={[styles.itemTitle, { color: theme.text }]}>{title}</Text><Text style={[styles.itemSub, { color: theme.muted }]}>{sub}</Text></View>{value ? <Text style={[styles.itemValue, { color: theme.text }]}>{value}</Text> : null}</View>{note ? <Text style={[styles.bodyBig, { color: theme.muted }]}>{note}</Text> : null}<Actions onEdit={onEdit} onDelete={onDelete} /></Card>; }
function Actions({ onEdit, onDelete }) { return <View style={styles.actions}>{onEdit ? <Pressable onPress={onEdit}><Text style={styles.editText}>Düzenle / Favori</Text></Pressable> : <View />}{onDelete ? <Pressable onPress={onDelete}><Text style={styles.deleteText}>Sil</Text></Pressable> : null}</View>; }
function Delete({ onPress }) { return <Pressable onPress={onPress}><Text style={styles.deleteText}>Sil</Text></Pressable>; }
function Empty({ theme, icon, text }) { return <Card theme={theme}><View style={styles.empty}><MaterialCommunityIcons name={icon} size={36} color="#31B5FF" /><Text style={[styles.emptyText, { color: theme.muted }]}>{text}</Text></View></Card>; }
function Nav({ theme, active, setActive }) { const items = [['panel', 'Panel', 'home'], ['finans', 'Finans', 'wallet'], ['butce', 'Bütçe', 'calculator'], ['antalya', 'Antalya', 'map-marker'], ['ayar', 'Ayar', 'cog']]; return <View style={[styles.nav, { backgroundColor: theme.nav, borderColor: theme.line }]}>{items.map(([id, label, icon]) => <Pressable key={id} onPress={() => setActive(id)} style={styles.navItem}>{active === id ? <LinearGradient colors={['#0FE0A0', '#2E6BFF']} style={styles.navActive}><MaterialCommunityIcons name={icon} size={24} color="white" /></LinearGradient> : <MaterialCommunityIcons name={icon} size={26} color={theme.muted} />}<Text style={[styles.navLabel, { color: active === id ? theme.text : theme.muted }]}>{label}</Text></Pressable>)}</View>; }

